    public static function avatar(string $gender, int $index): string
    {
        $segment = $gender === 'female' ? 'women' : 'men';
        $photoIndex = ($index % 90) + 1;

        return "https://randomuser.me/api/portraits/{$segment}/{$photoIndex}.jpg";
    }

    public static function egyptPhone(int $index): string
    {
        return '+2010'.str_pad((string) (1234560 + $index), 7, '0', STR_PAD_LEFT);
    }

    public static function userProfile(int $index, string $role, ?string $gender = null): array
    {
        $gender = $gender ?? ($index % 2 === 0 ? 'male' : 'female');
        $firstNames = $gender === 'female' ? self::femaleNames() : self::maleNames();
        $first = $firstNames[$index % count($firstNames)];
        $family = self::familyNames()[($index + intdiv($index, 3)) % count(self::familyNames())];
        $emailHandle = $first['en'].'.'.$family['en'].($index + 1);

        return [
            'name' => $first['ar'].' '.$family['ar'],
            'first_name' => $first['ar'],
            'last_name' => $family['ar'],
            'username' => Str::lower($first['en'].$family['en'].($index + 1)),
            'email' => $emailHandle.'@kid-coder.test',
            'phone_number' => self::egyptPhone($index),
            'profile_picture' => self::avatar($gender, $index),
            'avatar' => self::avatar($gender, $index + 20),
            'role' => $role,
            'is_admin' => $role === 'admin',
            'is_staff' => in_array($role, ['admin', 'instructor'], true),
            'is_superuser' => $role === 'admin' && $index === 0,
            'is_active' => $role !== 'student' || ($index % 7 !== 0),
            'is_verified' => $role !== 'student' || ($index % 5 !== 0),
            'instructor_verified' => $role === 'instructor' ? $index % 4 !== 0 : false,
        ];
    }

